from abc import ABC, abstractmethod

class SupplyChainPartner(ABC):
    def __init__(self, id, name, contact):
        self.id = id
        self.name = name
        self.contact = contact

    @abstractmethod
    def supply(self):
        pass

    @abstractmethod
    def receive_order(self):
        pass

class Manufacturer(SupplyChainPartner):
    def supply(self):
        print(f"Manufacturer {self.name} is supplying products.")

    def receive_order(self):
        print(f"Manufacturer {self.name} received an order.")

class Supplier(SupplyChainPartner):
    def supply(self):
        print(f"Supplier {self.name} is delivering products.")

    def receive_order(self):
        print(f"Supplier {self.name} received an order.")

def default_test():
    # This function will test the implementation of the subclasses.
    # Do not modify this function.
    try:
        manufacturer = Manufacturer(1, "Acme Corp", "acme@example.com")
        supplier = Supplier(2, "Supply Solutions", "supply@example.com")

        manufacturer.supply()  # Expected output: Manufacturer Acme Corp is supplying products.
        manufacturer.receive_order()  # Expected output: Manufacturer Acme Corp received an order.

        supplier.supply()  # Expected output: Supplier Supply Solutions is delivering products.
        supplier.receive_order()  # Expected output: Supplier Supply Solutions received an order.

        return "PASS"
    except Exception as e:
        return f"FAIL: {str(e)}"
